import numpy as np
import random
from collections import defaultdict

def solve(jobs: list[list[dict]]) -> list[list[dict]]:
    # Extract number of jobs and machines
    num_jobs = len(jobs)
    num_machines = max(max(op['machine'] for op in job) for job in jobs) + 1

    # Initialize Q-table: state -> action -> value
    # State: (current_time, machine_availability, job_progress)
    # Action: which operation to schedule next
    Q = defaultdict(lambda: defaultdict(float))

    # Hyperparameters
    alpha = 0.1  # learning rate
    gamma = 0.9  # discount factor
    epsilon = 0.3  # exploration rate
    episodes = 1000

    # Helper function to get state representation
    def get_state(schedule, current_time):
        # Machine availability: time when each machine becomes free
        machine_free = [0] * num_machines
        for job in schedule:
            for op in job:
                if 'start' in op:
                    end_time = op['start'] + op['duration']
                    if end_time > machine_free[op['machine']]:
                        machine_free[op['machine']] = end_time

        # Job progress: how many operations completed for each job
        job_progress = [0] * num_jobs
        for job_idx, job in enumerate(schedule):
            for op in job:
                if 'start' in op:
                    job_progress[job_idx] += 1

        return (tuple(machine_free), tuple(job_progress))

    # Helper function to get available operations
    def get_available_ops(schedule):
        available = []
        for job_idx, job in enumerate(schedule):
            # Find the next operation that hasn't been scheduled yet
            for op_idx, op in enumerate(job):
                if 'start' not in op:
                    # Check if previous operation in this job is completed
                    if op_idx == 0 or 'start' in job[op_idx - 1]:
                        available.append((job_idx, op_idx))
                    break
        return available

    # Helper function to calculate makespan
    def calculate_makespan(schedule):
        makespan = 0
        for job in schedule:
            for op in job:
                if 'start' in op:
                    end_time = op['start'] + op['duration']
                    if end_time > makespan:
                        makespan = end_time
        return makespan

    # Training loop
    best_schedule = None
    best_makespan = float('inf')

    for episode in range(episodes):
        # Reset schedule
        schedule = [job.copy() for job in jobs]
        for job in schedule:
            for op in job:
                op = op.copy()

        current_time = 0

        while True:
            state = get_state(schedule, current_time)
            available_ops = get_available_ops(schedule)

            if not available_ops:
                break

            # Epsilon-greedy action selection
            if random.random() < epsilon:
                # Explore: choose random available operation
                job_idx, op_idx = random.choice(available_ops)
            else:
                # Exploit: choose operation with highest Q-value
                max_q = -float('inf')
                best_action = None

                for job_idx, op_idx in available_ops:
                    action = (job_idx, op_idx)
                    if Q[state][action] > max_q:
                        max_q = Q[state][action]
                        best_action = action

                if best_action is None:
                    job_idx, op_idx = random.choice(available_ops)
                else:
                    job_idx, op_idx = best_action

            # Schedule the operation
            op = schedule[job_idx][op_idx]
            machine = op['machine']
            duration = op['duration']

            # Find earliest start time for this operation
            # Must be after machine is free and after previous operation in job
            machine_free_time = 0
            for j in schedule:
                for o in j:
                    if 'start' in o and o['machine'] == machine:
                        end_time = o['start'] + o['duration']
                        if end_time > machine_free_time:
                            machine_free_time = end_time

            prev_op_end = 0
            if op_idx > 0 and 'start' in schedule[job_idx][op_idx - 1]:
                prev_op_end = schedule[job_idx][op_idx - 1]['start'] + schedule[job_idx][op_idx - 1]['duration']

            start_time = max(machine_free_time, prev_op_end)
            op['start'] = start_time

            # Calculate reward (negative makespan)
            makespan = calculate_makespan(schedule)
            reward = -makespan

            # Update Q-value
            new_state = get_state(schedule, start_time + duration)
            max_future_q = max(Q[new_state].values()) if Q[new_state] else 0

            Q[state][(job_idx, op_idx)] = (1 - alpha) * Q[state][(job_idx, op_idx)] + \
                                          alpha * (reward + gamma * max_future_q)

            current_time = start_time + duration

        # Track best schedule found
        current_makespan = calculate_makespan(schedule)
        if current_makespan < best_makespan:
            best_makespan = current_makespan
            best_schedule = [job.copy() for job in schedule]
            for job in best_schedule:
                for op in job:
                    op = op.copy()

    # Return the best schedule found
    return best_schedule
